                                                          <node ID="ID_97982720" BACKGROUND_COLOR="#141414" COLOR="#ffffff" POSITION="right" HGAP_QUANTITY="185 px" VSHIFT_QUANTITY="-1237 px" MIN_WIDTH="523" MAX_WIDTH="523">
                                                            <font NAME="LiberationSans" SIZE="49" BOLD="true"/>
                                                            <edge COLOR="#9a7c93" WIDTH="4"/>
                                                            <richcontent TYPE="NODE"><html><head/><body>
                                                              <p><span style="font-family: LiberationSans; font-size: 49pt; color: #ffffff; font-weight: bold">Moses</span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 49pt; color: #ffffff; font-weight: bold">"The born one"</span></p>
                                                              <p>&#160;</p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">Raised as Egyptian royalty.</span></p>
                                                              <p>&#160;</p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">After he kills an Egyptian taskmaster </span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">for beating a Hebrew slave he</span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">flees to </span><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-weight: bold; font-style: italic">Midian</span><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">, and meets his wife</span></p>
                                                              <p>&#160;</p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic"> called by God to liberate the Hebrews</span></p>
                                                              <p>&#160;</p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">He acts as a mediator between God</span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">and humanity.</span></p>
                                                              <p>&#160;</p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">He attains his connection with God</span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">while working near mount Sinai</span></p>
                                                              <p>&#160;</p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">He remains relatively poor materialistically </span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">his whole life, and is not allowed to enter</span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">the promised land, because he disrespected </span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">the Lord in front of his people </span></p>
                                                            </body></html></richcontent>
                                                            <node ID="ID_315857096" BACKGROUND_COLOR="#141414" COLOR="#ffffff" POSITION="right" HGAP_QUANTITY="146 px" VSHIFT_QUANTITY="-277 px" MIN_WIDTH="232" MAX_WIDTH="232">
                                                              <font NAME="LiberationSans" SIZE="28" BOLD="true"/>
                                                              <edge COLOR="#be4781" WIDTH="4"/>
