                                                                <edge COLOR="#e68447" WIDTH="4"/>
                                                                <richcontent TYPE="NODE"><html><head/><body>
                                                                  <p><span style="font-family: LiberationSans; font-size: 38pt; color: #ffffff; font-weight: bold">Gershom</span></p>
                                                                  <p><span style="font-family: LiberationSans; font-size: 38pt; color: #ffffff">"Stranger there"</span></p>
                                                                  <p>&#160;</p>
                                                                  <p><span style="font-family: LiberationSans; font-size: 38pt; color: #ffffff; font-style: italic">"I have been a stranger (ger)</span></p>
                                                                  <p><span style="font-family: LiberationSans; font-size: 38pt; color: #ffffff; font-style: italic"> in a foreign land."</span></p>
                                                                </body></html></richcontent>
                                                              </node>
                                                              <node ID="ID_342696304" BACKGROUND_COLOR="#141414" COLOR="#ffffff" POSITION="right" HGAP_QUANTITY="208 px" VSHIFT_QUANTITY="-230 px" MIN_WIDTH="311" MAX_WIDTH="311">
