                                                            <font NAME="LiberationSans" SIZE="26" BOLD="true"/>
                                                            <edge COLOR="#9a7c93" WIDTH="4"/>
                                                            <richcontent TYPE="NODE"><html><head/><body>
                                                              <p><span style="font-family: LiberationSans; font-size: 26pt; color: #ffffff; font-weight: bold">Miriam</span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 26pt; color: #ffffff; font-style: italic">"Bitterness" or</span></p>
                                                              <p><span style="font-family: LiberationSans; font-size: 26pt; color: #ffffff; font-style: italic">"Bitter Sea"</span></p>
                                                              <p>&#160;</p>
                                                              <p><span style="font-family: LiberationSans; font-size: 26pt; color: #ffffff; font-style: italic">The prophetess</span></p>
                                                            </body></html></richcontent>
                                                          </node>
                                                        </node>
