                                                                  <node ID="ID_344920336" BACKGROUND_COLOR="#141414" COLOR="#ffffff" POSITION="left" HGAP_QUANTITY="344 px" VSHIFT_QUANTITY="-580 px" MIN_WIDTH="548" MAX_WIDTH="548">
