                        <node ID="ID_218866176" BACKGROUND_COLOR="#cdd4f3" COLOR="#ffffff" POSITION="right" HGAP_QUANTITY="31 px" VSHIFT_QUANTITY="1915 px" MIN_WIDTH="551" MAX_WIDTH="551">
                          <font NAME="LiberationSans" SIZE="38" BOLD="true"/>
                          <edge COLOR="#a3dd8a" WIDTH="4"/>
                          <richcontent TYPE="NODE"><html><head/><body>
                            <p><span style="font-family: LiberationSans; font-size: 38pt; color: #ffffff; font-weight: bold">Ham</span></p>
                            <p><span style="font-family: LiberationSans; font-size: 38pt; color: #ffffff">"The Hot One"</span></p>
                            <p>&#160;</p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">saw his father's nakedness,</span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">but his brothers refused</span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">to look. </span></p>
                            <p>&#160;</p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">This culture decided to openly </span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">expose and take advantage of</span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">old world knowledge. </span></p>
                            <p>&#160;</p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">They build powerful empires that</span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff">they can't sustain long term</span></p>
                            <p>&#160;</p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">For insight into Ham cultures, </span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">look at the earliest known powerful empires, </span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">like ancient Egypt, Mesopotamia,</span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">and many others. </span></p>
                            <p>&#160;</p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">Ham culture intermixed with Shem and Japheth</span></p>
                            <p><span style="font-family: LiberationSans; font-size: 22pt; color: #ffffff; font-style: italic">on many occasions along the march of time</span></p>
                          </body></html></richcontent>
